// Logging Interceptor
// ============================================================

func loggingUnaryInterceptor(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (interface{}, error) {
	log.Printf("[Interceptor] Incoming RPC: %s", info.FullMethod)
	resp, err := handler(ctx, req)
	if err != nil {
		log.Printf("[Interceptor] RPC %s failed: %v", info.FullMethod, err)
	} else {
		log.Printf("[Interceptor] RPC %s completed successfully", info.FullMethod)
	}
	return resp, err
}

