// Main - Server Setup
// ============================================================

func main() {
	port := ":50051"

	lis, err := net.Listen("tcp", port)
	if err != nil {
		log.Fatalf("Failed to listen on %s: %v", port, err)
	}

	// Create gRPC server with interceptor
	grpcServer := grpc.NewServer(
		grpc.UnaryInterceptor(loggingUnaryInterceptor),
	)

	// Initialize service handlers
	userService := NewUserManagementServer()
	orderService := NewOrderServer()
	paymentService := NewPaymentServer()

	// Register services
	grpcServer.RegisterService(&userServiceDesc, userService)
	grpcServer.RegisterService(&orderServiceDesc, orderService)
	grpcServer.RegisterService(&paymentServiceDesc, paymentService)

	// SECURITY: gRPC reflection is intentionally NOT enabled.
	// Reflection exposes all service definitions, methods, and message types
	// to any client that connects. This is a security risk because:
	// 1. It allows attackers to discover all available RPCs and their schemas
	// 2. It enables automated enumeration and fuzzing of services
	// 3. It leaks internal API structure that should not be publicly visible
	// 4. Tools like grpcurl/grpcui can fully introspect the server
	//
	// Even in development environments, reflection should be avoided as
	// development configs often leak into staging/production.
	//
	// Instead, share .proto files directly with authorized developers
	// or use a private proto registry for service discovery.
	//
	// DO NOT add: reflection.Register(grpcServer)

	log.Printf("==============================================")
	log.Printf("  Microservices gRPC Server")
	log.Printf("  Listening on %s", port)
	log.Printf("  gRPC Reflection: DISABLED (security)")
	log.Printf("==============================================")
	log.Printf("Registered services:")
	log.Printf("  - microservices.UserManagementService")
	log.Printf("    - CreateUser, GetUser, ListUsers, DeleteUser")
	log.Printf("  - microservices.OrderService")
	log.Printf("    - CreateOrder, GetOrder, ListOrdersByUser, UpdateOrderStatus, CancelOrder")
	log.Printf("  - microservices.PaymentService")
	log.Printf("    - ProcessPayment, GetPayment, GetPaymentByOrder, RefundPayment")
	log.Printf("==============================================")

	// Seed some test data
	seedTestData(userService, orderService, paymentService)

	if err := grpcServer.Serve(lis); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}

func seedTestData(userSvc *UserManagementServer, orderSvc *OrderServer, paymentSvc *PaymentServer) {
	ctx := context.Background()

	user1, _ := userSvc.CreateUser(ctx, "Alice Johnson", "alice@example.com")
	user2, _ := userSvc.CreateUser(ctx, "Bob Smith", "bob@example.com")
	userSvc.CreateUser(ctx, "Charlie Brown", "charlie@example.com")

	order1, _ := orderSvc.CreateOrder(ctx, user1.ID, 99.99)
	order2, _ := orderSvc.CreateOrder(ctx, user1.ID, 49.50)
	order3, _ := orderSvc.CreateOrder(ctx, user2.ID, 199.00)

	paymentSvc.ProcessPayment(ctx, order1.ID, order1.Amount, "CREDIT_CARD")
	paymentSvc.ProcessPayment(ctx, order2.ID, order2.Amount, "PAYPAL")
	paymentSvc.ProcessPayment(ctx, order3.ID, order3.Amount, "BANK_TRANSFER")

	orderSvc.UpdateOrderStatus(ctx, order1.ID, "COMPLETED")
	orderSvc.UpdateOrderStatus(ctx, order2.ID, "SHIPPED")

	log.Printf("[Seed] Test data seeded successfully")
}